"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["593905"],{581874(e){e.exports=JSON.parse('{"tag":{"label":"decor","permalink":"/dst-api-webdocs/docs/tags/decor","allTagsPath":"/dst-api-webdocs/docs/tags","count":17,"items":[{"id":"game-scripts/prefabs/carnival_decor","title":"Carnival Decor","description":"Creates interactive carnival-themed decor prefabs with workable, loot-dropping, and physics properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_decor"},{"id":"game-scripts/prefabs/carnivaldecor_eggride","title":"Carnivaldecor Eggride","description":"A networked arcade decoration item that, when activated, plays an animation sequence and sound loop for a set duration before automatically turning off; it supports activation via direct use or token exchange.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivaldecor_eggride"},{"id":"game-scripts/prefabs/carnivaldecor_figure","title":"Carnivaldecor Figure","description":"Creates a carnival-themed decorative statue that can be deployed in the world and yields loot when hammered.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivaldecor_figure"},{"id":"game-scripts/prefabs/decor_lamp","title":"Decor Lamp","description":"A decorative lantern prefab that provides adjustable ambient light and consumes cave fuel when active.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_lamp"},{"id":"game-scripts/prefabs/farm_decor","title":"Farm Decor","description":"Defines prefabs for decorative landscape items used in farm-related environments, such as rocks, sticks, and fence posts.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_decor"},{"id":"game-scripts/prefabs/flies","title":"Flies","description":"A decorative prefab that emits ambient fly sounds and animations based on player proximity, typically used for atmospheric effects in environments like caves and swamps.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flies"},{"id":"game-scripts/prefabs/furniture_decor_items","title":"Furniture decor items","description":"Generates prefabs for small decorative furniture items with floatable and burnable properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/furniture_decor_items"},{"id":"game-scripts/prefabs/lavaarena_crowdstand","title":"Lavaarena Crowdstand","description":"Provides client-side visual decoration for the Lava Arena spectator stands, including banners, fences, and audience members.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_crowdstand"},{"id":"game-scripts/prefabs/lavaarena_rhinobuff","title":"Lavaarena Rhinobuff","description":"A visual effect prefab used in the Lava Arena event to provide a decorative rhinoceros-themed buff animation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_rhinobuff"},{"id":"game-scripts/prefabs/lavaarena_spawner","title":"Lavaarena Spawner","description":"Creates a non-networked decorative entity with animated scratch marks and spawner teeth used for visual context in the Lava Arena biome.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_spawner"},{"id":"game-scripts/map/static_layouts/moonaltarrockidol","title":"Moonaltarrockidol","description":"Static layout data defining the placement and configuration of a moon altar rock idol in a static map layout.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/moonaltarrockidol"},{"id":"game-scripts/prefabs/moonglass_stalactites","title":"Moonglass Stalactites","description":"Generates three prefabs for non-blocking moonglass stalactite decorative entities used in world environments.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonglass_stalactites"},{"id":"game-scripts/prefabs/phonograph","title":"Phonograph","description":"Defines the Phonograph prefab, a decorative machine that plays music records and tends nearby farm plants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/phonograph"},{"id":"game-scripts/prefabs/quagmire_oldstructures","title":"Quagmire Oldstructures","description":"Defines prefabs for Quagmire-era decorative and structural props (e.g., rubble, carriage, clocktower) used in the old structures theme.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_oldstructures"},{"id":"game-scripts/prefabs/vault_chandelier","title":"Vault Chandelier","description":"Defines two prefabs: a broken chandelier and a decor variant, used for static environmental props in the Vault area.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_chandelier"},{"id":"game-scripts/prefabs/wurt_tentacle_warning","title":"Wurt Tentacle Warning","description":"A non-persistent visual decoration entity used as a warning indicator for Wurt\'s tentacle attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wurt_tentacle_warning"},{"id":"game-scripts/prefabs/yotc_carrat_rug","title":"Yotc Carrat Rug","description":"Decorative floor item that plays idle and animation states upon placement or burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_rug"}],"unlisted":false}}')}}]);